  1256→int
  1257→ldap_msgtype( LDAPMessage *lm )
  1258→{
  1259→	assert( lm != NULL );
  1260→	return ( lm != NULL ) ? (int)lm->lm_msgtype : -1;
  1261→}
  1262→
  1263→
  1264→int
  1265→ldap_msgid( LDAPMessage *lm )
  1266→{
  1267→	assert( lm != NULL );
  1268→
  1269→	return ( lm != NULL ) ? lm->lm_msgid : -1;
  1270→}
  1271→
  1272→
  1273→const char *
  1274→ldap_int_msgtype2str( ber_tag_t tag )
  1275→{
  1276→	switch( tag ) {
  1277→	case LDAP_RES_ADD: return "add";
  1278→	case LDAP_RES_BIND: return "bind";
  1279→	case LDAP_RES_COMPARE: return "compare";
  1280→	case LDAP_RES_DELETE: return "delete";
  1281→	case LDAP_RES_EXTENDED: return "extended-result";
  1282→	case LDAP_RES_INTERMEDIATE: return "intermediate";
  1283→	case LDAP_RES_MODIFY: return "modify";
  1284→	case LDAP_RES_RENAME: return "rename";
  1285→	case LDAP_RES_SEARCH_ENTRY: return "search-entry";
  1286→	case LDAP_RES_SEARCH_REFERENCE: return "search-reference";
  1287→	case LDAP_RES_SEARCH_RESULT: return "search-result";
  1288→	}
  1289→	return "unknown";
  1290→}
  1291→
  1292→int
  1293→ldap_msgfree( LDAPMessage *lm )
  1294→{
  1295→	LDAPMessage	*next;
  1296→	int		type = 0;
  1297→
  1298→	Debug0( LDAP_DEBUG_TRACE, "ldap_msgfree\n" );
  1299→
  1300→	for ( ; lm != NULL; lm = next ) {
  1301→		next = lm->lm_chain;
  1302→		type = lm->lm_msgtype;
  1303→		ber_free( lm->lm_ber, 1 );
  1304→		LDAP_FREE( (char *) lm );
  1305→	}
  1306→
  1307→	return type;
  1308→}
  1309→
  1310→/*
  1311→ * ldap_msgdelete - delete a message.  It returns:
  1312→ *	0	if the entire message was deleted
  1313→ *	-1	if the message was not found, or only part of it was found
  1314→ */
  1315→int
  1316→ldap_msgdelete( LDAP *ld, int msgid )
  1317→{
  1318→	LDAPMessage	*lm, *prev;
  1319→	int		rc = 0;
  1320→
  1321→	assert( ld != NULL );
  1322→
  1323→	Debug2( LDAP_DEBUG_TRACE, "ldap_msgdelete ld=%p msgid=%d\n",
  1324→		(void *)ld, msgid );
  1325→
  1326→	LDAP_MUTEX_LOCK( &ld->ld_res_mutex );
  1327→	prev = NULL;
  1328→	for ( lm = ld->ld_responses; lm != NULL; lm = lm->lm_next ) {
  1329→		if ( lm->lm_msgid == msgid ) {
  1330→			break;
  1331→		}
  1332→		prev = lm;
  1333→	}
  1334→
  1335→	if ( lm == NULL ) {
  1336→		rc = -1;
  1337→
  1338→	} else {
  1339→		if ( prev == NULL ) {
  1340→			ld->ld_responses = lm->lm_next;
  1341→		} else {
  1342→			prev->lm_next = lm->lm_next;
  1343→		}
  1344→	}
  1345→	LDAP_MUTEX_UNLOCK( &ld->ld_res_mutex );
  1346→	if ( lm ) {
  1347→		switch ( ldap_msgfree( lm ) ) {
  1348→		case LDAP_RES_SEARCH_ENTRY:
  1349→		case LDAP_RES_SEARCH_REFERENCE:
  1350→		case LDAP_RES_INTERMEDIATE:
  1351→			rc = -1;
  1352→			break;
  1353→
  1354→		default:
  1355→			break;
  1356→		}
  1357→	}
  1358→
  1359→	return rc;
  1360→}
  1361→
  1362→
  1363→/*
  1364→ * ldap_abandoned
  1365→ *
  1366→ * return the location of the message id in the array of abandoned
  1367→ * message ids, or -1
  1368→ */
  1369→static int
  1370→ldap_abandoned( LDAP *ld, ber_int_t msgid )
  1371→{
  1372→	int	ret, idx;
  1373→	assert( msgid >= 0 );
  1374→
  1375→	LDAP_MUTEX_LOCK( &ld->ld_abandon_mutex );
  1376→	ret = ldap_int_bisect_find( ld->ld_abandoned, ld->ld_nabandoned, msgid, &idx );
  1377→	LDAP_MUTEX_UNLOCK( &ld->ld_abandon_mutex );
  1378→	return ret;
  1379→}
  1380→
  1381→/*
  1382→ * ldap_mark_abandoned
  1383→ */
  1384→static int
  1385→ldap_mark_abandoned( LDAP *ld, ber_int_t msgid )
  1386→{
  1387→	int	ret, idx;
  1388→
  1389→	assert( msgid >= 0 );
  1390→	LDAP_MUTEX_LOCK( &ld->ld_abandon_mutex );
  1391→	ret = ldap_int_bisect_find( ld->ld_abandoned, ld->ld_nabandoned, msgid, &idx );
  1392→	if (ret <= 0) {		/* error or already deleted by another thread */
  1393→		LDAP_MUTEX_UNLOCK( &ld->ld_abandon_mutex );
  1394→		return ret;
  1395→	}
  1396→	/* still in abandoned array, so delete */
  1397→	ret = ldap_int_bisect_delete( &ld->ld_abandoned, &ld->ld_nabandoned,
  1398→		msgid, idx );
  1399→	LDAP_MUTEX_UNLOCK( &ld->ld_abandon_mutex );
  1400→	return ret;
  1401→}
